class Solution:
    def getDistances(self, arr):
        n = len(arr)
        res = [0] * n
        for i in range(n):
            total = 0
            for j in range(n):
                if j != i and arr[j] == arr[i]:
                    total += abs(i - j)
            res[i] = total
        return res

