var getDistances = function(arr) {
    const n = arr.length;
    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const v = arr[i];
        if (!groups.has(v)) groups.set(v, []);
        groups.get(v).push(i);
    }
    const res = new Array(n).fill(0);
    for (const idxs of groups.values()) {
        const k = idxs.length;
        const prefix = new Array(k + 1).fill(0);
        for (let i = 0; i < k; i++) prefix[i + 1] = prefix[i] + idxs[i];
        const total = prefix[k];
        for (let r = 0; r < k; r++) {
            const idx = idxs[r];
            const leftCount = r;
            const leftSum = prefix[r];
            const rightCount = k - r - 1;
            const rightSum = total - prefix[r + 1];
            res[idx] = (idx * leftCount - leftSum) + (rightSum - idx * rightCount);
        }
    }
    return res;
};
